// POST /authorize - Handle user login and consent
app.post('/authorize', (req, res) => {
  const {
    username,
    password,
    client_id,
    redirect_uri,
    scope,
    state,
    response_type,
    consent
  } = req.body;

  // Validate client again
  const validation = validateClient(client_id, redirect_uri);
  if (!validation.valid) {
    return res.status(400).send(renderError(validation.error));
  }

  const client = validation.client;
  const effectiveRedirectUri = redirect_uri || client.redirect_uris[0];

  // Authenticate user
  const user = users.get(username);
  if (!user || user.password !== password) {
    return res.send(renderLoginConsentForm({
      client_id,
      client_name: client.name,
      redirect_uri: effectiveRedirectUri,
      scope: scope || '',
      state: state || '',
      response_type,
      error: 'Invalid username or password'
    }));
  }

  // Check consent
  if (consent === 'deny') {
    const redirectUrl = new URL(effectiveRedirectUri);
    redirectUrl.searchParams.set('error', 'access_denied');
    redirectUrl.searchParams.set('error_description', 'The user denied the request');
    if (state) redirectUrl.searchParams.set('state', state);
    return res.redirect(redirectUrl.toString());
  }

  // Generate authorization code
  const code = generateToken(16);
  const codeData = {
    code,
    client_id,
    redirect_uri: effectiveRedirectUri,
    username: user.username,
    scope: scope || '',
    created_at: Date.now(),
    expires_at: Date.now() + 10 * 60 * 1000, // 10 minutes
    used: false
  };

  authorizationCodes.set(code, codeData);

  // Redirect back to client with authorization code
  const redirectUrl = new URL(effectiveRedirectUri);
  redirectUrl.searchParams.set('code', code);
  if (state) redirectUrl.searchParams.set('state', state);

  console.log(`[AUTH] Authorization code issued: ${code} for user: ${username}, client: ${client_id}`);
  res.redirect(redirectUrl.toString());
});

// POST /token - Token endpoint
app.post('/token', (req, res) => {
  const { grant_type, code, redirect_uri, client_id, client_secret } = req.body;

  // Also support client credentials in Authorization header
  let effectiveClientId = client_id;
  let effectiveClientSecret = client_secret;

  const authHeader = req.headers.authorization;
  if (authHeader && authHeader.startsWith('Basic ')) {
    const decoded = Buffer.from(authHeader.slice(6), 'base64').toString('utf8');
    const [headerClientId, headerClientSecret] = decoded.split(':');
    effectiveClientId = effectiveClientId || headerClientId;
    effectiveClientSecret = effectiveClientSecret || headerClientSecret;
  }

  // Validate grant_type
  if (grant_type !== 'authorization_code') {
    return res.status(400).json({
      error: 'unsupported_grant_type',
      error_description: 'Only "authorization_code" grant type is supported'
    });
  }

  // Validate client credentials
  if (!effectiveClientId || !effectiveClientSecret) {
    return res.status(401).json({
      error: 'invalid_client',
      error_description: 'Client authentication failed: missing client_id or client_secret'
    });
  }

  const client = clients.get(effectiveClientId);
  if (!client || client.client_secret !== effectiveClientSecret) {
    return res.status(401).json({
      error: 'invalid_client',
      error_description: 'Client authentication failed: invalid credentials'
    });
  }

  // Validate authorization code
  if (!code) {
    return res.status(400).json({
      error: 'invalid_request',
      error_description: 'Missing authorization code'
    });
  }

  const codeData = authorizationCodes.get(code);
  if (!codeData) {
    return res.status(400).json({
      error: 'invalid_grant',
      error_description: 'Invalid authorization code'
    });
  }

  // Check if code has been used (prevent replay)
  if (codeData.used) {
    // Revoke any tokens issued with this code (security measure)
    console.log(`[SECURITY] Authorization code reuse detected: ${code}`);
    authorizationCodes.delete(code);
    return res.status(400).json({
      error: 'invalid_grant',
      error_description: 'Authorization code has already been used'
    });
  }

  // Check if code has expired
  if (Date.now() > codeData.expires_at) {
    authorizationCodes.delete(code);
    return res.status(400).json({
      error: 'invalid_grant',
      error_description: 'Authorization code has expired'
    });
  }

  // Validate client_id matches
  if (codeData.client_id !== effectiveClientId) {
    return res.status(400).json({
      error: 'invalid_grant',
      error_description: 'Authorization code was not issued to this client'
    });
  }

  // Validate redirect_uri matches
  if (redirect_uri && redirect_uri !== codeData.redirect_uri) {
    return res.status(400).json({
      error: 'invalid_grant',
      error_description: 'redirect_uri does not match the one used in the authorization request'
    });
  }

  // Mark code as used
  codeData.used = true;

  // Generate access token and refresh token
  const accessToken = generateToken(32);
  const refreshToken = generateToken(32);
  const expiresIn = 3600; // 1 hour

  const tokenData = {
    access_token: accessToken,
    refresh_token: refreshToken,
    token_type: 'Bearer',
    expires_in: expiresIn,
    scope: codeData.scope,
    client_id: effectiveClientId,
    username: codeData.username,
    created_at: Date.now(),
    expires_at: Date.now() + expiresIn * 1000
  };

  accessTokens.set(accessToken, tokenData);

  console.log(`[TOKEN] Access token issued for user: ${codeData.username}, client: ${effectiveClientId}`);

  res.json({
    access_token: accessToken,
    token_type: 'Bearer',
    expires_in: expiresIn,
    refresh_token: refreshToken,
    scope: codeData.scope
  });
});

// GET /userinfo - Protected resource endpoint (for testing)
app.get('/userinfo', (req, res) => {
  const authHeader = req.headers.authorization;
  if (!authHeader || !authHeader.startsWith('Bearer ')) {
    return res.status(401).json({
      error: 'invalid_token',
      error_description: 'Missing or invalid Bearer token'
    });
  }

  const token = authHeader.slice(7);
  const tokenData = accessTokens.get(token);

  if (!tokenData) {
    return res.status(401).json({
      error: 'invalid_token',
      error_description: 'Token not found or has been revoked'
    });
  }

  if (Date.now() > tokenData.expires_at) {
    accessTokens.delete(token);
    return res.status(401).json({
      error: 'invalid_token',
      error_description: 'Token has expired'
    });
  }

  const user = users.get(tokenData.username);
  res.json({
    sub: user.username,
    name: user.name,
    scope: tokenData.scope
  });
});

// GET /token/introspect - Token introspection endpoint
app.post('/token/introspect', (req, res) => {
  const { token } = req.body;

  // Authenticate client
  const authHeader = req.headers.authorization;
  let clientId, clientSecret;

  if (authHeader && authHeader.startsWith('Basic ')) {
    const decoded = Buffer.from(authHeader.slice(6), 'base64').toString('utf8');
    [clientId, clientSecret] = decoded.split(':');
  } else {
    clientId = req.body.client_id;
    clientSecret = req.body.client_secret;
  }

  const client = clients.get(clientId);
  if (!client || client.client_secret !== clientSecret) {
    return res.status(401).json({ error: 'invalid_client' });
  }

  if (!token) {
    return res.json({ active: false });
  }

  const tokenData = accessTokens.get(token);
  if (!tokenData || Date.now() > tokenData.expires_at) {
    return res.json({ active: false });
  }

  res.json({
    active: true,
    scope: tokenData.scope,
    client_id: tokenData.client_id,
    username: tokenData.username,
    token_type: tokenData.token_type,
    exp: Math.floor(tokenData.expires_at / 1000),
    iat: Math.floor(tokenData.created_at / 1000)
  });
});

// POST /token/revoke - Token revocation endpoint
app.post('/token/revoke', (req, res) => {
  const { token } = req.body;

  // Authenticate client
  const authHeader = req.headers.authorization;
  let clientId, clientSecret;

  if (authHeader && authHeader.startsWith('Basic ')) {
    const decoded = Buffer.from(authHeader.slice(6), 'base64').toString('utf8');
    [clientId, clientSecret] = decoded.split(':');
  } else {
    clientId = req.body.client_id;
    clientSecret = req.body.client_secret;
  }

  const client = clients.get(clientId);
  if (!client || client.client_secret !== clientSecret) {
    return res.status(401).json({ error: 'invalid_client' });
  }

  if (token && accessTokens.has(token)) {
    accessTokens.delete(token);
    console.log(`[REVOKE] Token revoked by client: ${clientId}`);
  }

  // Always return 200 per RFC 7009
  res.status(200).send();
});

